import React, { useState, useEffect, useRef } from 'react';
import { ChatSession as GenAIChatSession, GenerateContentResponse } from '@google/genai';
import { createSimulationSession } from '../services/geminiService';
import { ChatMessage, Pathway, UserProfile } from '../types';
import { Send, User, Gamepad2, AlertCircle, XCircle } from 'lucide-react';
import ConversationalInput from './ConversationalInput';

interface SimulationSessionProps {
  pathway: Pathway;
  userProfile: UserProfile;
  onExit: () => void;
}

const SimulationSession: React.FC<SimulationSessionProps> = ({ pathway, userProfile, onExit }) => {
  const [chat, setChat] = useState<GenAIChatSession | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize Simulation Session
    try {
      const context = `User Name: ${userProfile.name}. Location/Context: ${userProfile.situation}. Interest: ${pathway.title}`;
      const session = createSimulationSession(pathway.title, context);
      setChat(session);

      // Initial trigger to get the AI to set the scene
      setIsLoading(true);
      session.sendMessage("START_SIMULATION").then((response) => {
          setMessages([{
            id: 'init',
            role: 'model',
            text: response.text || "Ready to start simulation..."
          }]);
          setIsLoading(false);
      });

    } catch (e) {
      console.error("Failed to init simulation", e);
    }
  }, [pathway, userProfile]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || !chat || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chat.sendMessage(userMsg.text);

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: response.text || "..."
      }]);

    } catch (err) {
      console.error("Simulation error", err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-900/95 backdrop-blur-sm flex items-center justify-center p-4">
        <div className="w-full max-w-3xl bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden flex flex-col h-[85vh] animate-fadeIn">

            {/* Header */}
            <div className="p-4 bg-slate-800 border-b border-slate-700 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-500 p-2 rounded-lg">
                        <Gamepad2 className="w-6 h-6 text-white" />
                    </div>
                    <div>
                        <h2 className="text-white font-bold text-lg">Career Simulator</h2>
                        <p className="text-indigo-300 text-xs uppercase tracking-wider">Role: {pathway.title}</p>
                    </div>
                </div>
                <button onClick={onExit} className="text-slate-400 hover:text-white transition-colors">
                    <XCircle className="w-8 h-8" />
                </button>
            </div>

            {/* Chat Area */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-900/50">
                {messages.map((msg) => (
                <div 
                    key={msg.id} 
                    className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
                >
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-700' : 'bg-indigo-600'}`}>
                    {msg.role === 'user' ? <User className="w-5 h-5 text-slate-300" /> : <Gamepad2 className="w-5 h-5 text-white" />}
                    </div>

                    <div className={`max-w-[80%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div className={`p-5 rounded-2xl shadow-lg leading-relaxed ${
                            msg.role === 'user' 
                                ? 'bg-slate-800 text-white rounded-tr-none border border-slate-700' 
                                : 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-50 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap text-base">{msg.text}</div>
                        </div>
                    </div>
                </div>
                ))}

                {isLoading && (
                    <div className="flex items-center gap-3 text-indigo-400 animate-pulse">
                        <Gamepad2 className="w-5 h-5" />
                        <span className="text-sm font-mono">Generating scenario outcome...</span>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-slate-800 border-t border-slate-700">
                <ConversationalInput 
                    value={input}
                    onChange={setInput}
                    onSubmit={handleSend}
                    placeholder="Describe what you would do..."
                    autoFocus={true}
                    enableVoice={true}
                />
                 <div className="mt-3 flex items-start gap-2 text-xs text-slate-400">
                    <AlertCircle className="w-3 h-3 mt-0.5 text-indigo-400" />
                    <p>You are in a simulation. There are no wrong answers, just consequences. Try to act as you would in real life.</p>
                </div>
            </div>
        </div>
    </div>
  );
};

export default SimulationSession;

import React, { useState, useEffect, useRef } from 'react';
import { ChatSession as GenAIChatSession, GenerateContentResponse } from '@google/genai';
import { getChatSession } from '../services/geminiService';
import { ChatMessage, Source } from '../types';
import { Send, User, Sparkles, ExternalLink, Loader2, Search, BrainCircuit } from 'lucide-react';

const ChatSession: React.FC = () => {
  const [chat, setChat] = useState<GenAIChatSession | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    try {
      const session = getChatSession();
      setChat(session);

      setMessages([{
        id: 'init',
        role: 'model',
        text: "Hello! I'm your Agentic Career Researcher.\n\nI can verify facts, check job market trends, or find scholarship deadlines using real-time Google Search.\n\nTry asking: 'What is the starting salary for a Data Analyst in Lagos right now?'"
      }]);
    } catch (e) {
      console.error("Failed to init chat", e);
    }
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || !chat || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const thinkingMsgId = 'thinking-' + Date.now();
      // Agentic "Thinking" State
      setMessages(prev => [...prev, { id: thinkingMsgId, role: 'model', text: '', isTyping: true, toolUse: 'Processing request...' }]);

      const result = await chat.sendMessageStream(userMsg.text);

      let fullText = '';
      let sources: Source[] = [];
      let toolActivity = 'Generating response...';

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullText += c.text;
        }

        // Visualize Grounding as "Agent Action"
        if (c.candidates?.[0]?.groundingMetadata?.groundingChunks) {
          toolActivity = 'Searching web sources...';
          c.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web?.uri && chunk.web?.title) {
              sources.push({ title: chunk.web.title, uri: chunk.web.uri });
            }
          });
        }

        setMessages(prev => {
          const newHistory = [...prev];
          const lastIdx = newHistory.findIndex(m => m.id === thinkingMsgId);
          if (lastIdx !== -1) {
            newHistory[lastIdx] = {
              ...newHistory[lastIdx],
              text: fullText,
              isTyping: false,
              sources: sources.length > 0 ? sources : undefined,
              toolUse: sources.length > 0 ? 'Verified with Google Search' : undefined
            };
          }
          return newHistory;
        });
      }

      // Cleanup dupes
      sources = sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i);

      setMessages(prev => {
          const newHistory = [...prev];
          const lastIdx = newHistory.findIndex(m => m.id === thinkingMsgId);
          if (lastIdx !== -1) {
             newHistory[lastIdx] = { ...newHistory[lastIdx], isTyping: false, sources: sources.length > 0 ? sources : undefined };
          }
          return newHistory;
      });

    } catch (err) {
      console.error("Chat error", err);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: "I'm having trouble connecting right now. Please try again." 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn">
      {/* Agent Header */}
      <div className="p-4 border-b border-slate-100 bg-slate-900 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg">
            <BrainCircuit className="w-5 h-5 text-white" />
          </div>
          <div>
            <h3 className="font-bold">CareerSage Agent</h3>
            <p className="text-xs text-emerald-200">Autonomous Research Mode</p>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 shadow-md ${msg.role === 'user' ? 'bg-white' : 'bg-emerald-600'}`}>
              {msg.role === 'user' ? <User className="w-5 h-5 text-slate-700" /> : <Sparkles className="w-5 h-5 text-white" />}
            </div>

            <div className={`flex flex-col max-w-[85%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>

              {/* Tool Usage Indicator */}
              {msg.role === 'model' && msg.toolUse && (
                  <div className="flex items-center gap-2 mb-2 px-3 py-1 bg-white border border-slate-200 rounded-full text-xs text-slate-500 font-medium shadow-sm w-fit animate-fadeIn">
                      <Search className="w-3 h-3 text-emerald-500" />
                      {msg.toolUse}
                  </div>
              )}

              <div 
                className={`px-6 py-4 rounded-2xl shadow-sm text-sm md:text-base leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-slate-800 text-white rounded-tr-none' 
                    : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                }`}
              >
                {msg.isTyping && !msg.text ? (
                  <div className="flex gap-1 h-6 items-center">
                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                  </div>
                ) : (
                  <div className="whitespace-pre-wrap">{msg.text}</div>
                )}
              </div>

              {/* Sources Display */}
              {msg.sources && msg.sources.length > 0 && (
                <div className="mt-3 bg-white p-3 rounded-xl border border-blue-100 shadow-sm w-full">
                   <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 flex items-center gap-1"><ExternalLink className="w-3 h-3" /> Verified Sources</p>
                   <div className="flex flex-wrap gap-2">
                    {msg.sources.map((src, i) => (
                        <a 
                        key={i} 
                        href={src.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="block w-full text-xs text-blue-600 hover:underline truncate"
                        >
                        {src.title}
                        </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask me to find scholarships, salaries, or courses..."
            disabled={isLoading}
            className="w-full pl-6 pr-14 py-4 bg-slate-50 border border-slate-200 rounded-full focus:outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all text-sm shadow-inner"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 p-2 bg-emerald-600 text-white rounded-full hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg"
          >
            {isLoading ? <Loader2 className="w-6 h-6 animate-spin p-1" /> : <Send className="w-5 h-5 m-0.5" />}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatSession;

import React, { useState } from 'react';
import { Compass, Sparkles, Mic, MessageSquare, MessageCircle } from 'lucide-react';
import { AppState, CareerAdviceResponse, FileData, UserProfile, Pathway } from './types';
import { generateCareerAdvice } from './services/geminiService';
import InputForm from './components/InputForm';
import ResultView from './components/ResultView';
import LoadingScreen from './components/LoadingScreen';
import VoiceSession from './components/VoiceSession';
import ChatSession from './components/ChatSession';
import SimulationSession from './components/SimulationSession';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<CareerAdviceResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [mode, setMode] = useState<'text' | 'voice' | 'chat'>('text');

  // State for Simulation
  const [simulationPathway, setSimulationPathway] = useState<Pathway | null>(null);

  // Lifted Input State
  const [profile, setProfile] = useState<UserProfile>({
    name: '',
    situation: '',
    interests: [],
    constraints: [],
    dreams: '',
    concerns: ''
  });
  const [inputStep, setInputStep] = useState(0);

  const handleAnalyze = async (text: string, files: FileData[]) => {
    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      const data = await generateCareerAdvice(text, files);
      setResult(data);
      setAppState(AppState.RESULTS);
    } catch (err: any) {
      console.error(err);
      let msg = "Something went wrong while connecting to CareerSage.";
      if (err.message) msg += ` Details: ${err.message}`;

      setErrorMsg(msg);
      setAppState(AppState.ERROR);
    }
  };

  const getProfileNarrative = () => {
    return `
      My name is ${profile.name || "Student"}. 
      Current Situation: ${profile.situation}.
      My Interests: ${profile.interests.join(', ')}.
      My Constraints/Context: ${profile.constraints.join(', ')}.
      My Dreams/Goals: ${profile.dreams}.
      Additional Concerns: ${profile.concerns}.
      (Note: This request was triggered from a Voice Session).
    `;
  };

  const handleVoiceReportGeneration = () => {
    setMode('text');
    handleAnalyze(getProfileNarrative(), []);
  };

  const startSimulation = (pathway: Pathway) => {
    setSimulationPathway(pathway);
    setAppState(AppState.SIMULATION);
  };

  const exitSimulation = () => {
    setSimulationPathway(null);
    setAppState(AppState.RESULTS);
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setErrorMsg(null);
    setInputStep(0);
    setSimulationPathway(null);
    setProfile({
        name: '',
        situation: '',
        interests: [],
        constraints: [],
        dreams: '',
        concerns: ''
    });
  };

  const switchMode = (newMode: 'text' | 'voice' | 'chat') => {
    setMode(newMode);
    if (appState === AppState.SIMULATION) {
        exitSimulation(); // Exit sim if changing tabs
    }
    if (appState !== AppState.IDLE) {
      if (appState === AppState.RESULTS && newMode === 'text') {
          // Keep results
      } else {
        if (appState === AppState.ANALYZING) setAppState(AppState.IDLE);
      }
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 md:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer group" onClick={resetApp}>
            <div className="bg-emerald-600 p-1.5 rounded-xl shadow-sm group-hover:bg-emerald-700 transition-colors">
              <Compass className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-emerald-800 to-teal-600">
              CareerSage
            </h1>
          </div>

          {/* Mode Toggle */}
          <div className="flex bg-slate-100 rounded-full p-1 border border-slate-200/60 shadow-inner">
            <button
              onClick={() => switchMode('text')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'text' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <MessageSquare className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">Advisor</span>
            </button>
            <button
              onClick={() => switchMode('voice')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'voice' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Mic className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">Voice Call</span>
            </button>
            <button
              onClick={() => switchMode('chat')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'chat' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <MessageCircle className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">Quick Chat</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-5xl mx-auto px-4 md:px-6 py-6 md:py-8 relative">

        {mode === 'voice' && (
          <VoiceSession 
            onEndSession={() => switchMode('text')} 
            userProfile={profile}
            onGenerateReport={handleVoiceReportGeneration}
          />
        )}

        {mode === 'chat' && (
           <ChatSession />
        )}

        {mode === 'text' && (
          <>
            {appState === AppState.IDLE && (
              <div className="animate-fadeIn">
                <div className="text-center max-w-xl mx-auto mb-8 md:mb-10">
                  <div className="inline-flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 text-xs font-medium rounded-full mb-3 border border-emerald-100">
                     <Sparkles className="w-3 h-3" /> AI Career Counselor
                  </div>
                  <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-3 tracking-tight">
                     Let's find your path.
                  </h2>
                  <p className="text-slate-500 text-sm md:text-base leading-relaxed">
                    I'm here to help you navigate your future with realistic, personalized advice. 
                  </p>
                </div>

                <InputForm 
                  profile={profile}
                  setProfile={setProfile}
                  currentStep={inputStep}
                  setCurrentStep={setInputStep}
                  onSubmit={handleAnalyze} 
                  isLoading={false} 
                />

              </div>
            )}

            {appState === AppState.ANALYZING && <LoadingScreen />}

            {appState === AppState.ERROR && (
              <div className="max-w-md mx-auto text-center py-20 animate-fadeIn">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-red-100 mb-6">
                  <Compass className="w-8 h-8 text-red-600" />
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Analysis Failed</h3>
                <p className="text-slate-600 mb-4">{errorMsg}</p>
                <button
                  onClick={() => setAppState(AppState.IDLE)}
                  className="px-6 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors"
                >
                  Try Again
                </button>
              </div>
            )}

            {appState === AppState.RESULTS && result && (
              <ResultView 
                data={result} 
                onReset={resetApp} 
                onSimulate={startSimulation}
              />
            )}

            {appState === AppState.SIMULATION && simulationPathway && (
               <SimulationSession 
                  pathway={simulationPathway}
                  userProfile={profile}
                  onExit={exitSimulation}
               />
            )}
          </>
        )}
      </main>

      {/* Footer */}
      <footer className="py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-xs text-slate-400">
            Powered by Gemini 3 Pro • Educational Purpose Only
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

