                <form onSubmit={handleSetupSubmit} className="w-full max-w-md space-y-4">
                    <div className="text-left">
                        <label className="text-xs font-bold text-indigo-400 uppercase tracking-wider ml-1">Your Name</label>
                        <input 
                            type="text" 
                            required
                            value={setupData.name}
                            onChange={(e) => setSetupData({...setupData, name: e.target.value})}
                            className="w-full bg-slate-800 border border-slate-600 rounded-xl p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all mt-1"
                            placeholder="e.g. David"
                        />
                    </div>
                    <div className="text-left">
                        <label className="text-xs font-bold text-indigo-400 uppercase tracking-wider ml-1">Job Role to Simulate</label>
                        <div className="relative">
                            <Briefcase className="absolute left-3 top-3.5 w-5 h-5 text-slate-500" />
                            <input 
                                type="text" 
                                required
                                value={setupData.role}
                                onChange={(e) => setSetupData({...setupData, role: e.target.value})}
                                className="w-full bg-slate-800 border border-slate-600 rounded-xl p-3 pl-10 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all mt-1 font-semibold"
                                placeholder="e.g. Digital Marketer, Civil Engineer..."
                            />
                        </div>
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-gradient-to-r from-indigo-600 to-violet-600 py-4 rounded-xl font-bold text-lg hover:shadow-lg hover:shadow-indigo-500/25 transition-all transform hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-2"
                    >
                        <Play className="w-5 h-5 fill-current" /> Start Simulation
                    </button>
                </form>
            </div>
        </div>
    );
  }

  // --- RENDER: CHAT INTERFACE ---
  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto bg-slate-900 rounded-2xl shadow-2xl border border-slate-700 overflow-hidden animate-fadeIn relative">
        {/* Header */}
        <div className="p-4 bg-slate-800 border-b border-slate-700 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-indigo-500 p-2 rounded-lg">
                    <Gamepad2 className="w-6 h-6 text-white" />
                </div>
                <div>
                    <h2 className="text-white font-bold text-lg hidden sm:block">Career Simulator</h2>
                    <div className="flex items-center gap-1 text-indigo-300 text-xs uppercase tracking-wider">
                         <span>Running Scenario:</span>
                         <span className="font-bold text-white bg-white/10 px-2 py-0.5 rounded">{initialRole || setupData.role}</span>
                    </div>
                </div>
            </div>
            <button onClick={onExit} className="text-slate-400 hover:text-white transition-colors bg-white/5 p-2 rounded-lg hover:bg-red-500/20 hover:text-red-400">
                <span className="text-xs font-bold mr-2">EXIT</span>
                <XCircle className="w-5 h-5 inline" />
            </button>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-slate-900/50">
            {messages.map((msg) => (
            <div 
                key={msg.id} 
                className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-700' : 'bg-indigo-600'}`}>
