            ))}

            {isLoading && (
                <div className="flex items-center gap-3 text-indigo-400 animate-pulse pl-14">
                    <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '100ms'}}></div>
                    <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></div>
                    <span className="text-xs font-mono uppercase tracking-widest opacity-70">Computing Outcome...</span>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-slate-800 border-t border-slate-700">
            <ConversationalInput 
                value={input}
                onChange={setInput}
                onSubmit={handleSend}
                placeholder="What do you want to do next?"
                autoFocus={true}
                enableVoice={true}
            />
                <div className="mt-3 flex items-start gap-2 text-xs text-slate-400 px-1">
