export const createSimulationSession = (role: string, context: string): GenAIChatSession => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  const ai = new GoogleGenAI({ apiKey });

  return ai.chats.create({
    model: 'gemini-2.5-flash', // Flash for lower latency in roleplay
    config: {
      systemInstruction: `
        You are an interactive Career Simulator Engine.
        Your Goal: Immerse the user in a "Day in the Life" scenario for the role of: ${role}.

        Rules:
        1. Start by setting a realistic, challenging scene appropriate for an entry-level ${role}.
           (e.g., for a Developer: "The production site is down, here is the error log...")
           (e.g., for a Digital Marketer: "The client hates the campaign draft 2 hours before launch...")
        2. Keep the scene culturally relevant to the user's context: ${context}.
        3. Do NOT just ask "What do you do?". Give them specific details/data/visuals in text.
        4. Wait for the user's response.
        5. React to their choice. If good, advance the plot. If bad, show the consequence (gently).
        6. Keep turns short (max 3 sentences).
        7. After 5 turns, or if the user solves it, conclude with a "Performance Review" and ask if they liked the job.
      `
    }
  });
};

