import React, { useState } from 'react';
import { Compass, Sparkles, Mic, MessageSquare, MessageCircle, Gamepad2, History } from 'lucide-react';
import { AppState, CareerAdviceResponse, FileData, UserProfile, Pathway, ChatMessage, SavedSession } from './types';
import { generateCareerAdvice } from './services/geminiService';
import { saveSession } from './services/storage';
import InputForm from './components/InputForm';
import ResultView from './components/ResultView';
import LoadingScreen from './components/LoadingScreen';
import VoiceSession from './components/VoiceSession';
import ChatSession from './components/ChatSession';
import SimulationSession from './components/SimulationSession';
import HistoryModal from './components/HistoryModal';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<CareerAdviceResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [mode, setMode] = useState<'text' | 'voice' | 'chat' | 'simulator'>('text');

  // State for Simulation
  const [simulationParams, setSimulationParams] = useState<{role: string, context: string} | null>(null);

  // State for Chat History restoration
  const [chatHistoryData, setChatHistoryData] = useState<ChatMessage[] | undefined>(undefined);

  // State for History Modal
  const [showHistory, setShowHistory] = useState(false);

  // Lifted Input State
  const [profile, setProfile] = useState<UserProfile>({
    name: '',
    situation: '',
    interests: [],
    constraints: [],
    dreams: '',
    concerns: ''
  });
  const [inputStep, setInputStep] = useState(0);

  const handleAnalyze = async (text: string, files: FileData[]) => {
    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      const data = await generateCareerAdvice(text, files);
      setResult(data);
      setAppState(AppState.RESULTS);
      // Auto-save successful results
      saveSession('advisor', data);
    } catch (err: any) {
      console.error(err);
      let msg = "Something went wrong while connecting to CareerSage.";
      if (err.message) msg += ` Details: ${err.message}`;

      setErrorMsg(msg);
      setAppState(AppState.ERROR);
    }
  };

  const getProfileNarrative = () => {
    return `
      My name is ${profile.name || "Student"}. 
      Current Situation: ${profile.situation}.
      My Interests: ${profile.interests.join(', ')}.
      My Constraints/Context: ${profile.constraints.join(', ')}.
      My Dreams/Goals: ${profile.dreams}.
      Additional Concerns: ${profile.concerns}.
      (Note: This request was triggered from a Voice Session).
    `;
  };

  const handleVoiceReportGeneration = () => {
    setMode('text');
    handleAnalyze(getProfileNarrative(), []);
  };

  const startSimulation = (pathway: Pathway) => {
    setSimulationParams({
      role: pathway.title,
      context: `User Name: ${profile.name || 'User'}. Background: ${profile.situation || 'N/A'}. Interests: ${profile.interests.join(', ')}.`
    });
    setMode('simulator');
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setErrorMsg(null);
    setInputStep(0);
    setSimulationParams(null);
    setChatHistoryData(undefined); // Clear chat history reset
    setProfile({
        name: '',
        situation: '',
        interests: [],
        constraints: [],
        dreams: '',
        concerns: ''
    });
  };

  const switchMode = (newMode: 'text' | 'voice' | 'chat' | 'simulator') => {
    // If we switch away from chat voluntarily, we clear the restored history
    // so next time it starts fresh (unless loaded from history again)
    if (mode === 'chat' && newMode !== 'chat') {
        setChatHistoryData(undefined);
    }
    setMode(newMode);

    if (mode === 'simulator' && newMode !== 'simulator') {
      setSimulationParams(null);
    }
  };

  const handleManualSimulationStart = () => {
    setSimulationParams(null); 
    setMode('simulator');
  };

  const handleRestoreSession = (session: SavedSession) => {
    setShowHistory(false);
    if (session.type === 'advisor') {
        setMode('text');
        setResult(session.data as CareerAdviceResponse);
        setAppState(AppState.RESULTS);
    } else if (session.type === 'chat') {
        setChatHistoryData(session.data as ChatMessage[]);
        setMode('chat');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-4 md:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer group" onClick={resetApp}>
            <div className="bg-emerald-600 p-1.5 rounded-xl shadow-sm group-hover:bg-emerald-700 transition-colors">
              <Compass className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-emerald-800 to-teal-600 hidden md:block">
              CareerSage
            </h1>
          </div>

          <div className="flex items-center gap-2">
             {/* Mode Toggle */}
            <div className="flex bg-slate-100 rounded-full p-1 border border-slate-200/60 shadow-inner overflow-x-auto">
                <button
                onClick={() => switchMode('text')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-all duration-300 ${mode === 'text' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                <MessageSquare className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Advisor</span>
                </button>
                <button
                onClick={() => switchMode('voice')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-all duration-300 ${mode === 'voice' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                <Mic className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Voice Call</span>
                </button>
                <button
                onClick={() => switchMode('chat')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-all duration-300 ${mode === 'chat' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                <MessageCircle className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Quick Chat</span>
                </button>
                <button
                onClick={handleManualSimulationStart}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all duration-300 ${mode === 'simulator' ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-600 hover:bg-indigo-50'}`}
                >
                <Gamepad2 className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Simulator</span>
                </button>
            </div>

            {/* History Button */}
            <button 
                onClick={() => setShowHistory(true)}
                className="p-2.5 rounded-full bg-slate-100 text-slate-600 hover:bg-emerald-50 hover:text-emerald-700 transition-colors border border-slate-200"
                title="History"
            >
                <History className="w-4 h-4" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-5xl mx-auto px-4 md:px-6 py-6 md:py-8 relative">

        {mode === 'voice' && (
          <VoiceSession 
            onEndSession={() => switchMode('text')} 
            userProfile={profile}
            onGenerateReport={handleVoiceReportGeneration}
          />
        )}

        {mode === 'chat' && (
           <ChatSession initialMessages={chatHistoryData} />
        )}

        {mode === 'simulator' && (
            <SimulationSession 
              initialRole={simulationParams?.role}
              initialContext={simulationParams?.context}
              onExit={() => switchMode('text')}
            />
        )}

        {mode === 'text' && (
          <>
            {appState === AppState.IDLE && (
              <div className="animate-fadeIn">
                <div className="text-center max-w-xl mx-auto mb-8 md:mb-10">
                  <div className="inline-flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 text-xs font-medium rounded-full mb-3 border border-emerald-100">
                     <Sparkles className="w-3 h-3" /> AI Career Counselor
                  </div>
                  <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-3 tracking-tight">
                     Let's find your path.
                  </h2>
                  <p className="text-slate-500 text-sm md:text-base leading-relaxed">
                    I'm here to help you navigate your future with realistic, personalized advice. 
                  </p>
                </div>

                <InputForm 
                  profile={profile}
                  setProfile={setProfile}
                  currentStep={inputStep}
                  setCurrentStep={setInputStep}
                  onSubmit={handleAnalyze} 
                  isLoading={false} 
                />

              </div>
            )}

            {appState === AppState.ANALYZING && <LoadingScreen />}

            {appState === AppState.ERROR && (
              <div className="max-w-md mx-auto text-center py-20 animate-fadeIn">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-red-100 mb-6">
                  <Compass className="w-8 h-8 text-red-600" />
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Analysis Failed</h3>
                <p className="text-slate-600 mb-4">{errorMsg}</p>
                <button
                  onClick={() => setAppState(AppState.IDLE)}
                  className="px-6 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors"
                >
                  Try Again
                </button>
              </div>
            )}

            {appState === AppState.RESULTS && result && (
              <ResultView 
                data={result} 
                onReset={resetApp} 
                onSimulate={startSimulation}
              />
            )}
          </>
        )}
      </main>

      <HistoryModal 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        onSelectSession={handleRestoreSession} 
      />

      {/* Footer */}
      <footer className="py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-xs text-slate-400">
            Powered by Gemini 3 Pro • Educational Purpose Only
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema, ChatSession as GenAIChatSession } from "@google/genai";
import { ANALYSIS_PROMPT } from "../constants";
import { CareerAdviceResponse, FileData, Pathway, FutureVision } from "../types";

const apiKey = process.env.API_KEY;

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentProfile: {
      type: Type.OBJECT,
      properties: {
        summary: { type: Type.STRING, description: "A concise summary of the student's profile (max 100 words)." },
        keyStrengths: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["summary", "keyStrengths"]
    },
    contextAnalysis: { type: Type.STRING, description: "Analysis of their situation and constraints." },
    reflection: { type: Type.STRING, description: "A 'What I Heard' section reflecting the user's story back to them." },
    practicalPathTitle: { type: Type.STRING, description: "Title of the realistic, near-term career path." },
    growthPathTitle: { type: Type.STRING, description: "Title of the aspirational, long-term career path." },
    reasoning: { type: Type.STRING, description: "Why these two paths were chosen." }
  },
  required: ["studentProfile", "contextAnalysis", "reflection", "practicalPathTitle", "growthPathTitle", "reasoning"]
};

const pathwaySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    fitReason: { type: Type.STRING, description: "Why this fits the user (max 2 sentences)." },
    requiredSkills: {
      type: Type.OBJECT,
      properties: {
        technical: { type: Type.ARRAY, items: { type: Type.STRING } },
        soft: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["technical", "soft"]
    },
    educationOptions: { type: Type.ARRAY, items: { type: Type.STRING } },
    timeline: { type: Type.STRING, description: "e.g., '6-12 months'" },
    challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
    actionSteps: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3-5 concrete starting steps." },
    marketReality: { type: Type.STRING, description: "Current demand and job availability." },
    realityCheck: { type: Type.STRING, description: "A grounded 'Reality Check' regarding common traps or local context." },
    salaryRange: {
      type: Type.OBJECT,
      properties: {
        min: { type: Type.NUMBER },
        max: { type: Type.NUMBER },
        currency: { type: Type.STRING, description: "Local currency code e.g. NGN, USD" }
      },
      required: ["min", "max", "currency"]
    },
    demandScore: { type: Type.NUMBER, description: "0 to 100" },
    growthScore: { type: Type.NUMBER, description: "0 to 100" }
  },
  required: ["title", "fitReason", "requiredSkills", "educationOptions", "timeline", "challenges", "actionSteps", "marketReality", "realityCheck", "salaryRange", "demandScore", "growthScore"]
};

// Helper to remove markdown code blocks if the model includes them
const cleanJson = (text: string): string => {
  return text.replace(/```json\n?|```/g, '').trim();
};

export const generateCareerAdvice = async (
  textInput: string,
  files: FileData[]
): Promise<CareerAdviceResponse> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });
  // Switched to Gemini 3 Pro for superior reasoning capabilities
  const modelName = "gemini-3-pro-preview"; 

  // Prepare input parts
  const analysisParts: any[] = [];
  if (files && files.length > 0) {
    files.forEach(file => {
      analysisParts.push({
        inlineData: { mimeType: file.mimeType, data: file.data }
      });
    });
  }
  analysisParts.push({ text: `Student Scenario: ${textInput}` });

  // --- STEP 1: ANALYSIS ---
  let analysisResult: any;
  try {
    console.log("Step 1: Analyzing Profile with Gemini 3 Pro...");
    const analysisResponse = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: analysisParts },
      config: {
        systemInstruction: ANALYSIS_PROMPT,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.3,
      }
    });

    if (!analysisResponse.text) throw new Error("Empty response from AI");
    analysisResult = JSON.parse(cleanJson(analysisResponse.text));
  } catch (error) {
    console.error("Step 1 Failed:", error);
    throw new Error("Failed to analyze profile. Please try again.");
  }

  // --- STEP 2 & 3: PATHWAY GENERATION (PARALLEL) ---
  console.log("Step 2: Generating Pathways...");

  const generatePathway = async (title: string, type: 'Practical' | 'Growth'): Promise<Pathway> => {
    const prompt = `
      Create a detailed ${type} Career Pathway for the role: "${title}".

      Student Context:
      ${JSON.stringify(analysisResult.studentProfile)}
      ${analysisResult.contextAnalysis}

      Requirements:
      - Be realistic for the African/Nigerian context if applicable.
      - Estimate salary ranges in local currency based on your knowledge.
      - Keep text concise and actionable.
      - Do NOT use placeholder values (e.g., 0, "TBD"). Estimate best available data.
    `;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: pathwaySchema,
        temperature: 0.4,
      }
    });

    if (!response.text) throw new Error("Empty pathway response");
    return JSON.parse(cleanJson(response.text)) as Pathway;
  };

  try {
    const [practicalPathway, growthPathway] = await Promise.all([
      generatePathway(analysisResult.practicalPathTitle, 'Practical'),
      generatePathway(analysisResult.growthPathTitle, 'Growth')
    ]);

    return {
      studentProfile: analysisResult.studentProfile,
      contextAnalysis: analysisResult.contextAnalysis,
      reflection: analysisResult.reflection,
      practicalPathway,
      growthPathway,
      closingMessage: "Your personalized career roadmap is ready. Remember, these are starting points—your journey is yours to define."
    };

  } catch (error) {
    console.error("Step 2 Failed:", error);
    throw new Error("Failed to generate detailed pathways. Please try again.");
  }
};

// --- VISION GENERATOR (IMAGE) ---

export const generateFutureVision = async (
  role: string, 
  userContext: string
): Promise<FutureVision> => {
  if (!apiKey) throw new Error("API Key is missing.");
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Generate a high-quality, photorealistic image of a young professional working as a ${role} in a modern African context (e.g. Lagos, Nairobi, or general urban setting).

    User Context for personalization: ${userContext}

    The image should be inspiring, warm, and professional. 
    Also, provide a short, 1-sentence motivational caption about their future success in this role.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // High quality image model
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      },
    });

    let imageData = "";
    let caption = `Your future as a ${role} looks bright.`;

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        imageData = part.inlineData.data;
      } else if (part.text) {
        caption = part.text;
      }
    }

    if (!imageData) throw new Error("No image generated");

    return { imageData, caption };
  } catch (e) {
    console.error("Image gen failed", e);
    throw e;
  }
};

// --- AGENTIC CHAT ---

export const getChatSession = (): GenAIChatSession => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  const ai = new GoogleGenAI({ apiKey });

  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `You are CareerSage's Agentic Assistant. 
      - Help the user by researching specific questions about scholarships, job markets, or education.
      - You have access to Google Search. USE IT proactively when asked for facts, dates, or prices.
      - Be concise, warm, and helpful.
      - Do NOT make up URLs. Only provide links found via the search tool.`,
      tools: [{ googleSearch: {} }] // Agentic Capability
    }
  });
};

// --- SIMULATION ENGINE ---

export const createSimulationSession = (role: string, context: string): GenAIChatSession => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  const ai = new GoogleGenAI({ apiKey });

  return ai.chats.create({
    model: 'gemini-2.5-flash', // Flash for lower latency in roleplay
    config: {
      systemInstruction: `
        You are an interactive Career Simulator Engine.
        Your Goal: Immerse the user in a "Day in the Life" scenario for the role of: ${role}.

        Rules:
        1. Start by setting a realistic, challenging scene appropriate for an entry-level ${role}.
           (e.g., for a Developer: "The production site is down, here is the error log...")
           (e.g., for a Digital Marketer: "The client hates the campaign draft 2 hours before launch...")
        2. Keep the scene culturally relevant to the user's context: ${context}.
        3. Do NOT just ask "What do you do?". Give them specific details/data/visuals in text.
        4. Wait for the user's response.
        5. React to their choice. If good, advance the plot. If bad, show the consequence (gently).
        6. Keep turns short (max 3 sentences).
        7. After 5 turns, or if the user solves it, conclude with a "Performance Review" and ask if they liked the job.
      `
    }
  });
};

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { Mic, MicOff, PhoneOff, Radio, Volume2, FileText } from 'lucide-react';
import { LIVE_SYSTEM_PROMPT } from '../constants';
import { arrayBufferToBase64, base64ToArrayBuffer, float32To16BitPCM, pcmToAudioBuffer } from '../utils/audio';
import { UserProfile } from '../types';

interface VoiceSessionProps {
  onEndSession: () => void;
  userProfile: UserProfile;
  onGenerateReport: () => void;
}

const VoiceSession: React.FC<VoiceSessionProps> = ({ onEndSession, userProfile, onGenerateReport }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [status, setStatus] = useState<'connecting' | 'connected' | 'error' | 'disconnected'>('connecting');
  const [volume, setVolume] = useState(0);

  // Audio Contexts & Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const analyzerRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Session & Playback State
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const scheduledSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const apiKey = process.env.API_KEY;

  useEffect(() => {
    startSession();
    return () => {
      cleanupSession();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const startSession = async () => {
    if (!apiKey) {
      setStatus('error');
      return;
    }

    try {
      setStatus('connecting');
      const ai = new GoogleGenAI({ apiKey });

      // Initialize Audio Contexts
      // Input: 16kHz for Gemini
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      // Output: 24kHz from Gemini
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Safety: Resume contexts if suspended (browser autoplay policy)
      if (inputAudioContextRef.current.state === 'suspended') await inputAudioContextRef.current.resume();
      if (outputAudioContextRef.current.state === 'suspended') await outputAudioContextRef.current.resume();

      outputNodeRef.current = outputAudioContextRef.current.createGain();
      outputNodeRef.current.connect(outputAudioContextRef.current.destination);

      // Setup Analyzer for visualizer
      analyzerRef.current = outputAudioContextRef.current.createAnalyser();
      analyzerRef.current.fftSize = 256;
      outputNodeRef.current.connect(analyzerRef.current);
      startVisualizer();

      // Get Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Build Context String from Profile
      const profileContext = userProfile.name 
        ? `\n\nUSER PROFILE DATA:\n${JSON.stringify(userProfile, null, 2)}` 
        : '\n\nUSER PROFILE: The user has not filled out the text form yet. Ask for their name and situation.';

      // Connect to Live API
      sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          systemInstruction: LIVE_SYSTEM_PROMPT + profileContext,
          tools: [{ googleSearch: {} }], // Enable Search Grounding for Voice
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
        },
        callbacks: {
          onopen: () => {
            console.log('Voice session opened');
            setStatus('connected');
            setIsConnected(true);
            setupAudioInput(stream);
          },
          onmessage: async (message: LiveServerMessage) => {
            await handleServerMessage(message);
          },
          onclose: () => {
            console.log('Voice session closed');
            setStatus('disconnected');
            setIsConnected(false);
          },
          onerror: (err) => {
            console.error('Voice session error:', err);
            setStatus('error');
          }
        }
      });

    } catch (error) {
      console.error('Failed to start session:', error);
      setStatus('error');
    }
  };

  const setupAudioInput = (stream: MediaStream) => {
    if (!inputAudioContextRef.current) return;

    inputSourceRef.current = inputAudioContextRef.current.createMediaStreamSource(stream);
    // Buffer size 4096, 1 input channel, 1 output channel
    processorRef.current = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);

    processorRef.current.onaudioprocess = (e) => {
      if (isMuted) return;

      const inputData = e.inputBuffer.getChannelData(0);
      // Convert Float32 to Int16 PCM ArrayBuffer
      const pcm16 = float32To16BitPCM(inputData);
      // Convert to Base64
      const base64Data = arrayBufferToBase64(new Uint8Array(pcm16));

      sessionPromiseRef.current?.then((session) => {
        session.sendRealtimeInput({
          media: {
            mimeType: 'audio/pcm;rate=16000',
            data: base64Data
          }
        });
      });
    };

    inputSourceRef.current.connect(processorRef.current);
    processorRef.current.connect(inputAudioContextRef.current.destination);
  };

  const handleServerMessage = async (message: LiveServerMessage) => {
    const serverContent = message.serverContent;

    // Handle Interruption (User spoke while AI was speaking)
    if (serverContent?.interrupted) {
      stopAllScheduledAudio();
      return;
    }

    // Handle Audio Output
    const modelTurn = serverContent?.modelTurn;
    if (modelTurn?.parts) {
      for (const part of modelTurn.parts) {
        if (part.inlineData && part.inlineData.data) {
          const base64Audio = part.inlineData.data;
          await queueAudioChunk(base64Audio);
        }
      }
    }
  };

  const queueAudioChunk = async (base64Audio: string) => {
    if (!outputAudioContextRef.current || !outputNodeRef.current) return;

    const ctx = outputAudioContextRef.current;

    // Ensure context is running (safety double-check)
    if (ctx.state === 'suspended') {
        try { await ctx.resume(); } catch(e) { console.warn(e); }
    }

    const audioBytes = base64ToArrayBuffer(base64Audio);

    try {
      const audioBuffer = await pcmToAudioBuffer(audioBytes, ctx, 24000);

      // Schedule playback
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(outputNodeRef.current);

      // Determine start time (cursor)
      const currentTime = ctx.currentTime;
      if (nextStartTimeRef.current < currentTime) {
        nextStartTimeRef.current = currentTime;
      }

      source.start(nextStartTimeRef.current);
      nextStartTimeRef.current += audioBuffer.duration;

      // Track source for cancellation
      scheduledSourcesRef.current.add(source);
      source.onended = () => {
        scheduledSourcesRef.current.delete(source);
      };

    } catch (e) {
      console.error("Error decoding audio chunk", e);
    }
  };

  const stopAllScheduledAudio = () => {
    scheduledSourcesRef.current.forEach(source => {
      try {
        source.stop();
      } catch (e) { /* ignore already stopped */ }
    });
    scheduledSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  };

  const startVisualizer = () => {
    const update = () => {
      if (analyzerRef.current) {
        const dataArray = new Uint8Array(analyzerRef.current.frequencyBinCount);
        analyzerRef.current.getByteFrequencyData(dataArray);
        // Calculate average volume
        const avg = dataArray.reduce((a, b) => a + b) / dataArray.length;
        setVolume(avg);
      }
      animationFrameRef.current = requestAnimationFrame(update);
    };
    update();
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const cleanupSession = () => {
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);

    sessionPromiseRef.current?.then(session => session.close()).catch(() => {});

    if (inputSourceRef.current) inputSourceRef.current.disconnect();
    if (processorRef.current) processorRef.current.disconnect();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();

    stopAllScheduledAudio();
  };

  // UI Components
  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] animate-fadeIn p-6">
      <div className="relative mb-12">
        {/* Visualizer Circle */}
        <div 
          className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-100 ease-out border-4 ${
            status === 'connected' ? 'border-emerald-500/30' : 'border-slate-200'
          }`}
          style={{
            transform: `scale(${1 + (volume / 255) * 0.5})`,
            boxShadow: `0 0 ${volume / 2}px rgba(16, 185, 129, 0.5)`
          }}
        >
          <div className="bg-white p-6 rounded-full shadow-lg relative z-10">
            {status === 'connecting' && <div className="animate-spin w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full" />}
            {status === 'connected' && <Radio className="w-16 h-16 text-emerald-600 animate-pulse" />}
            {status === 'error' && <PhoneOff className="w-16 h-16 text-red-500" />}
          </div>
        </div>

        {/* Status Text */}
        <div className="absolute -bottom-10 left-0 right-0 text-center">
            <p className="text-lg font-medium text-slate-700">
                {status === 'connecting' && "Connecting to CareerSage Voice..."}
                {status === 'connected' && (isMuted ? "Microphone Muted" : `Listening to ${userProfile.name || 'Student'}...`)}
                {status === 'error' && "Connection Failed"}
            </p>
        </div>
      </div>

      {/* Controls */}
      <div className="flex flex-col items-center gap-6 mt-8">
        <div className="flex items-center gap-6">
            <button
            onClick={toggleMute}
            className={`p-4 rounded-full transition-all ${
                isMuted 
                ? 'bg-red-100 text-red-600 hover:bg-red-200' 
                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
            }`}
            disabled={status !== 'connected'}
            title={isMuted ? "Unmute" : "Mute"}
            >
            {isMuted ? <MicOff className="w-6 h-6" /> : <Mic className="w-6 h-6" />}
            </button>

            <button
            onClick={onEndSession}
            className="bg-red-500 text-white px-8 py-3 rounded-full font-semibold hover:bg-red-600 shadow-lg hover:shadow-xl transition-all transform hover:scale-105 flex items-center gap-2"
            >
            <PhoneOff className="w-5 h-5" />
            End Call
            </button>
        </div>

        {status === 'connected' && (
            <button
                onClick={onGenerateReport}
                className="flex items-center gap-2 px-6 py-2.5 bg-emerald-600 text-white rounded-full font-semibold shadow-md hover:bg-emerald-700 hover:shadow-lg transition-all transform hover:-translate-y-0.5"
            >
                <FileText className="w-4 h-4" />
                Generate Written Plan
            </button>
        )}
      </div>

      <div className="mt-8 p-4 bg-emerald-50 text-emerald-800 rounded-lg max-w-md text-center text-sm">
        <p>Tip: I have read your profile. You can ask me to explain specific parts of it or ask for a full written report.</p>
      </div>
    </div>
  );
};

export default VoiceSession;

import React, { useState, useEffect, useRef } from 'react';
import { ChatSession as GenAIChatSession } from '@google/genai';
import { createSimulationSession } from '../services/geminiService';
import { ChatMessage } from '../types';
import { User, Gamepad2, AlertCircle, XCircle, Play, ChevronRight, Briefcase, Bot } from 'lucide-react';
import ConversationalInput from './ConversationalInput';

interface SimulationSessionProps {
  initialRole?: string;
  initialContext?: string;
  onExit: () => void;
}

const SimulationSession: React.FC<SimulationSessionProps> = ({ initialRole, initialContext, onExit }) => {
  const [chat, setChat] = useState<GenAIChatSession | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Setup State for manual entry
  const [needsSetup, setNeedsSetup] = useState(!initialRole);
  const [setupData, setSetupData] = useState({ role: initialRole || '', name: 'Student' });

  useEffect(() => {
    // If we have data immediately, start. Otherwise wait for setup form.
    if (!needsSetup && initialRole) {
      initSession(initialRole, initialContext || `User: ${setupData.name}`);
    }
  }, [initialRole, needsSetup]);

  const initSession = (role: string, context: string) => {
    try {
      const session = createSimulationSession(role, context);
      setChat(session);

      setIsLoading(true);
      session.sendMessage({ message: "START_SIMULATION" }).then((response) => {
          setMessages([{
            id: 'init',
            role: 'model',
            text: response.text || "Ready to start simulation..."
          }]);
          setIsLoading(false);
      });
    } catch (e) {
      console.error("Failed to init simulation", e);
    }
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSetupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (setupData.role.trim()) {
        setNeedsSetup(false);
        initSession(setupData.role, `User Name: ${setupData.name}. Custom Simulation Request.`);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || !chat || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chat.sendMessage({ message: userMsg.text });

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: response.text || "..."
      }]);

    } catch (err) {
      console.error("Simulation error", err);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "System Error: The simulation engine encountered a glitch. Please try again."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // --- RENDER: SETUP SCREEN ---
  if (needsSetup) {
    return (
        <div className="flex flex-col h-[600px] max-w-2xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
             <button onClick={onExit} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors z-10">
                <XCircle className="w-8 h-8" />
            </button>
            <div className="flex flex-col items-center justify-center h-full text-center space-y-8 p-8 relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-indigo-50 to-transparent"></div>

                <div className="relative z-10 bg-white p-4 rounded-full shadow-lg border border-indigo-100 mb-4 animate-bounce-slow">
                    <Gamepad2 className="w-12 h-12 text-indigo-600" />
                </div>

                <div className="relative z-10 max-w-md">
                    <h2 className="text-3xl font-bold mb-2 text-slate-800">Career Simulator</h2>
                    <p className="text-slate-500 text-lg">Experience a "Day in the Life" of your dream job before you commit.</p>
                </div>

                <form onSubmit={handleSetupSubmit} className="w-full max-w-sm space-y-5 relative z-10">
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Your Name</label>
                        <input 
                            type="text" 
                            required
                            value={setupData.name}
                            onChange={(e) => setSetupData({...setupData, name: e.target.value})}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 shadow-sm"
                            placeholder="e.g. David"
                        />
                    </div>
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Job Role to Simulate</label>
                        <div className="relative">
                            <Briefcase className="absolute left-3 top-3.5 w-5 h-5 text-slate-400" />
                            <input 
                                type="text" 
                                required
                                value={setupData.role}
                                onChange={(e) => setSetupData({...setupData, role: e.target.value})}
                                className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 pl-10 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 font-semibold shadow-sm"
                                placeholder="e.g. Digital Marketer"
                            />
                        </div>
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold text-lg hover:bg-indigo-700 hover:shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0 flex items-center justify-center gap-2"
                    >
                        <Play className="w-5 h-5 fill-current" /> Start Simulation
                    </button>
                </form>
            </div>
        </div>
    );
  }

  // --- RENDER: CHAT INTERFACE ---
  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
        {/* Header */}
        <div className="p-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-indigo-100 p-2 rounded-lg border border-indigo-200">
                    <Gamepad2 className="w-5 h-5 text-indigo-600" />
                </div>
                <div>
                    <h2 className="font-bold text-slate-800 text-lg hidden sm:block">Career Simulator</h2>
                    <div className="flex items-center gap-1.5 text-xs">
                         <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                         <span className="text-slate-500 uppercase tracking-wide font-medium">Scenario:</span>
                         <span className="font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">
                            {initialRole || setupData.role}
                         </span>
                    </div>
                </div>
            </div>
            <button 
                onClick={onExit} 
                className="group flex items-center gap-2 px-3 py-1.5 rounded-lg text-slate-500 hover:bg-red-50 hover:text-red-600 transition-colors border border-transparent hover:border-red-100"
            >
                <span className="text-xs font-bold group-hover:underline decoration-red-300">END SESSION</span>
                <XCircle className="w-5 h-5" />
            </button>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-slate-50/50">
            {messages.map((msg) => (
            <div 
                key={msg.id} 
                className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm border ${
                    msg.role === 'user' 
                        ? 'bg-indigo-600 border-indigo-600' 
                        : 'bg-white border-slate-200'
                }`}>
                    {msg.role === 'user' 
                        ? <User className="w-5 h-5 text-white" /> 
                        : <Bot className="w-5 h-5 text-indigo-600" />
                    }
                </div>

                <div className={`max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                    <div className={`p-5 rounded-2xl shadow-sm leading-relaxed text-sm md:text-base ${
                        msg.role === 'user' 
                            ? 'bg-indigo-600 text-white rounded-tr-none' 
                            : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                    }`}>
                        <div className="whitespace-pre-wrap">{msg.text}</div>
                    </div>
                    <span className="text-[10px] text-slate-400 mt-1 block px-1">
                        {msg.role === 'user' ? 'You' : 'Simulator'}
                    </span>
                </div>
            </div>
            ))}

            {isLoading && (
                <div className="flex items-center gap-3 text-slate-400 pl-14 animate-fadeIn">
                    <div className="flex gap-1 h-2">
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '100ms'}}></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></div>
                    </div>
                    <span className="text-xs font-medium">Simulating scenario...</span>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-slate-200">
            <ConversationalInput 
                value={input}
                onChange={setInput}
                onSubmit={handleSend}
                placeholder="Type your action or response..."
                autoFocus={true}
                enableVoice={true}
            />
            <div className="mt-3 flex items-start gap-2 text-xs text-slate-400 px-1 justify-center">
                <AlertCircle className="w-3 h-3 mt-0.5 text-indigo-400 flex-shrink-0" />
                <p>This is an AI roleplay. Your choices shape the outcome.</p>
            </div>
        </div>
    </div>
  );
};

