import { GoogleGenAI, Type, Schema, ChatSession as GenAIChatSession, FunctionDeclaration, Tool } from "@google/genai";
import { ANALYSIS_PROMPT } from "../constants";
import { CareerAdviceResponse, FileData, Pathway, FutureVision } from "../types";

const apiKey = process.env.API_KEY;

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentProfile: {
      type: Type.OBJECT,
      properties: {
        summary: { type: Type.STRING, description: "A concise summary of the student's profile (max 100 words)." },
        keyStrengths: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["summary", "keyStrengths"]
    },
    contextAnalysis: { type: Type.STRING, description: "Analysis of their situation and constraints." },
    reflection: { type: Type.STRING, description: "A 'What I Heard' section reflecting the user's story back to them." },
    practicalPathTitle: { type: Type.STRING, description: "Title of the realistic, near-term career path." },
    growthPathTitle: { type: Type.STRING, description: "Title of the aspirational, long-term career path." },
    reasoning: { type: Type.STRING, description: "Why these two paths were chosen." }
  },
  required: ["studentProfile", "contextAnalysis", "reflection", "practicalPathTitle", "growthPathTitle", "reasoning"]
};

const pathwaySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    fitReason: { type: Type.STRING, description: "Why this fits the user (max 2 sentences)." },
    requiredSkills: {
      type: Type.OBJECT,
      properties: {
        technical: { type: Type.ARRAY, items: { type: Type.STRING } },
        soft: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["technical", "soft"]
    },
    educationOptions: { type: Type.ARRAY, items: { type: Type.STRING } },
    timeline: { type: Type.STRING, description: "e.g., '6-12 months'" },
    challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
    actionSteps: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3-5 concrete starting steps." },
    marketReality: { type: Type.STRING, description: "Current demand and job availability." },
    realityCheck: { type: Type.STRING, description: "A grounded 'Reality Check' regarding common traps or local context." },
    salaryRange: {
      type: Type.OBJECT,
      properties: {
        min: { type: Type.NUMBER },
        max: { type: Type.NUMBER },
        currency: { type: Type.STRING, description: "Local currency code e.g. NGN, USD" }
      },
      required: ["min", "max", "currency"]
    },
    demandScore: { type: Type.NUMBER, description: "0 to 100" },
    growthScore: { type: Type.NUMBER, description: "0 to 100" }
  },
  required: ["title", "fitReason", "requiredSkills", "educationOptions", "timeline", "challenges", "actionSteps", "marketReality", "realityCheck", "salaryRange", "demandScore", "growthScore"]
};

// Helper to remove markdown code blocks if the model includes them
const cleanJson = (text: string): string => {
  return text.replace(/```json\n?|```/g, '').trim();
};

export const generateCareerAdvice = async (
  textInput: string,
  files: FileData[]
): Promise<CareerAdviceResponse> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });
  // Switched to Gemini 3 Pro for superior reasoning capabilities
  const modelName = "gemini-3-pro-preview"; 

  // Prepare input parts
  const analysisParts: any[] = [];
  if (files && files.length > 0) {
    files.forEach(file => {
      analysisParts.push({
        inlineData: { mimeType: file.mimeType, data: file.data }
      });
    });
  }
  analysisParts.push({ text: `Student Scenario: ${textInput}` });

  // --- STEP 1: ANALYSIS ---
  let analysisResult: any;
  try {
    console.log("Step 1: Analyzing Profile with Gemini 3 Pro...");
    const analysisResponse = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: analysisParts },
      config: {
        systemInstruction: ANALYSIS_PROMPT,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.3,
      }
    });

    if (!analysisResponse.text) throw new Error("Empty response from AI");
    analysisResult = JSON.parse(cleanJson(analysisResponse.text));
  } catch (error) {
    console.error("Step 1 Failed:", error);
    throw new Error("Failed to analyze profile. Please try again.");
  }

  // --- STEP 2 & 3: PATHWAY GENERATION (PARALLEL) ---
  console.log("Step 2: Generating Pathways...");

  const generatePathway = async (title: string, type: 'Practical' | 'Growth'): Promise<Pathway> => {
    const prompt = `
      Create a detailed ${type} Career Pathway for the role: "${title}".

      Student Context:
      ${JSON.stringify(analysisResult.studentProfile)}
      ${analysisResult.contextAnalysis}

      Requirements:
      - Be realistic for the African/Nigerian context if applicable.
      - Estimate salary ranges in local currency based on your knowledge.
      - Keep text concise and actionable.
      - Do NOT use placeholder values (e.g., 0, "TBD"). Estimate best available data.
    `;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: pathwaySchema,
        temperature: 0.4,
      }
    });

    if (!response.text) throw new Error("Empty pathway response");
    return JSON.parse(cleanJson(response.text)) as Pathway;
  };

  try {
    const [practicalPathway, growthPathway] = await Promise.all([
      generatePathway(analysisResult.practicalPathTitle, 'Practical'),
      generatePathway(analysisResult.growthPathTitle, 'Growth')
    ]);

    return {
      studentProfile: analysisResult.studentProfile,
      contextAnalysis: analysisResult.contextAnalysis,
      reflection: analysisResult.reflection,
      practicalPathway,
      growthPathway,
      closingMessage: "Your personalized career roadmap is ready. Remember, these are starting points—your journey is yours to define."
    };

  } catch (error) {
    console.error("Step 2 Failed:", error);
    throw new Error("Failed to generate detailed pathways. Please try again.");
  }
};

// --- VISION GENERATOR (IMAGE) ---

export const generateFutureVision = async (
  role: string, 
  userContext: string
): Promise<FutureVision> => {
  if (!apiKey) throw new Error("API Key is missing.");
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Generate a high-quality, photorealistic image of a young professional working as a ${role} in a modern African context (e.g. Lagos, Nairobi, or general urban setting).

    User Context for personalization: ${userContext}

    The image should be inspiring, warm, and professional. 
    Also, provide a short, 1-sentence motivational caption about their future success in this role.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // High quality image model
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      },
    });

    let imageData = "";
    let caption = `Your future as a ${role} looks bright.`;

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        imageData = part.inlineData.data;
      } else if (part.text) {
        caption = part.text;
      }
    }

    if (!imageData) throw new Error("No image generated");

    return { imageData, caption };
  } catch (e) {
    console.error("Image gen failed", e);
    throw e;
  }
};

// --- SIMULATION IMAGE GENERATION (FLASH 2.5) ---

export const generateSimulationImage = async (prompt: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");
  const ai = new GoogleGenAI({ apiKey });

  console.log("Generating simulation image with Gemini 2.5 Flash Image:", prompt);

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }]
    }
  });

  let imageData = "";
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      imageData = part.inlineData.data;
      break;
    }
  }

  if (!imageData) throw new Error("Failed to generate image.");
  return imageData;
};

export const editSimulationImage = async (base64Image: string, instruction: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");
  const ai = new GoogleGenAI({ apiKey });

  console.log("Editing simulation image with Gemini 2.5 Flash Image:", instruction);

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/png', data: base64Image } },
        { text: instruction }
      ]
    }
  });

  let imageData = "";
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      imageData = part.inlineData.data;
      break;
    }
  }

  if (!imageData) throw new Error("Failed to edit image.");
  return imageData;
};

// --- AGENTIC CHAT ---

export const getChatSession = (): GenAIChatSession => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  const ai = new GoogleGenAI({ apiKey });

  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `You are CareerSage's Agentic Assistant. 
      - Help the user by researching specific questions about scholarships, job markets, or education.
      - You have access to Google Search. USE IT proactively when asked for facts, dates, or prices.
      - Be concise, warm, and helpful.
      - Do NOT make up URLs. Only provide links found via the search tool.`,
      tools: [{ googleSearch: {} }] // Agentic Capability
    }
  });
};

// --- SIMULATION ENGINE ---

export const createSimulationSession = (role: string, context: string): GenAIChatSession => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }
  const ai = new GoogleGenAI({ apiKey });

  // Define tools for image generation and editing
  const tools: Tool[] = [
    {
      functionDeclarations: [
        {
          name: "generate_image",
          description: "Generate a realistic image of the current scene, object, or person. Use this to establish the setting or show the result of an action.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              prompt: { type: Type.STRING, description: "Detailed visual description of the scene." }
            },
            required: ["prompt"]
          }
        },
        {
          name: "edit_image",
          description: "Edit the PREVIOUSLY shown image based on the user's action. Use this to show changes, fixes, or worsening conditions.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              instruction: { type: Type.STRING, description: "Instruction for editing the image (e.g. 'Make the screen red with error', 'Fix the broken pipe')." }
            },
            required: ["instruction"]
          }
        }
      ]
    }
  ];

  return ai.chats.create({
    model: 'gemini-2.5-flash', // Flash for lower latency in roleplay and orchestration
    config: {
      tools: tools,
      systemInstruction: `
        You are the "Career Dungeon Master". Run a high-stakes, interactive job simulation for a ${role}.
        User Context: ${context}.

        OBJECTIVE:
        Simulate a "Day in the Life" that tests the user's decision-making, ethics, and competence.

        NARRATIVE FLOW:
        1. **The Setup**: Begin immediately. \`generate_image\` of the workspace (POV). Describe the setting and the first task.
        2. **The Complication**: Introduce a complex problem (e.g. equipment failure, difficult client, safety hazard, ethical dilemma).
        3. **Decision Points (CRITICAL)**: 
           - Present clear choices or open-ended problems.
           - *Example*: "The server room is overheating (Image). Do you (A) Shut down the core system (safe but costly) or (B) Try to patch the cooling live (risky)?"
        4. **Visual Consequences**: 
           - **If the user succeeds**: Use \`edit_image\` or \`generate_image\` to show the fixed state or reward.
           - **If the user fails**: Use \`generate_image\` to show the disaster (e.g., smoke, blue screen of death, angry boss face).
        5. **Evaluation**: After ~6 interactions, end with a "Performance Review": Score /100 and Feedback.

        BEHAVIOR RULES:
        - **Visual First**: Use tools frequently. The user should *see* the result of their actions.
        - **Editing**: If the user says "fix the logo" or "clean the desk", use \`edit_image\`.
        - **Adaptability**: If the user does something unexpected, roll with it and generate consequences.
        - **Tone**: Professional, immersive, and sometimes urgent.
        - **Context**: Ensure scenarios fit the African/Nigerian context (e.g. dealing with power/internet constraints).
      `
    }
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { ChatSession as GenAIChatSession, GenerateContentResponse } from '@google/genai';
import { createSimulationSession, generateSimulationImage, editSimulationImage } from '../services/geminiService';
import { ChatMessage } from '../types';
import { User, Gamepad2, AlertCircle, XCircle, Play, ChevronRight, Briefcase, Bot, Image as ImageIcon, Wand2, Loader2, RotateCcw } from 'lucide-react';
import ConversationalInput from './ConversationalInput';

interface SimulationSessionProps {
  initialRole?: string;
  initialContext?: string;
  onExit: () => void;
}

const SimulationSession: React.FC<SimulationSessionProps> = ({ initialRole, initialContext, onExit }) => {
  const [chat, setChat] = useState<GenAIChatSession | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [lastImage, setLastImage] = useState<string | null>(null); // Store last image for editing
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Setup State for manual entry
  const [needsSetup, setNeedsSetup] = useState(!initialRole);
  const [setupData, setSetupData] = useState({ role: initialRole || '', name: 'Student' });

  useEffect(() => {
    // If we have data immediately, start. Otherwise wait for setup form.
    if (!needsSetup && initialRole) {
      initSession(initialRole, initialContext || `User: ${setupData.name}`);
    }
  }, [initialRole, needsSetup]);

  const initSession = (role: string, context: string) => {
    try {
      const session = createSimulationSession(role, context);
      setChat(session);

      setIsLoading(true);
      // Trigger the "Setup" phase explicitly
      session.sendMessage({ message: "Begin the simulation. Generate the starting image of the workplace immediately." }).then((response) => {
          setMessages([{
            id: 'init',
            role: 'model',
            text: response.text || "Loading simulation..."
          }]);
          setIsLoading(false);
      });
    } catch (e) {
      console.error("Failed to init simulation", e);
    }
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSetupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (setupData.role.trim()) {
        setNeedsSetup(false);
        initSession(setupData.role, `User Name: ${setupData.name}. Custom Simulation Request.`);
    }
  };

  const handleRestart = () => {
    setMessages([]);
    setLastImage(null);
    if (initialRole) {
      initSession(initialRole, initialContext || `User: ${setupData.name}`);
    } else {
      initSession(setupData.role, `User Name: ${setupData.name}. Custom Simulation Request.`);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || !chat || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      let result = await chat.sendMessage({ message: userMsg.text });

      // Handle Tool Calls (Image Generation/Editing)
      // The loop handles cases where the model calls a tool, we send output, and it generates text.
      while (result.functionCalls && result.functionCalls.length > 0) {
        const call = result.functionCalls[0]; // Assuming single tool call for now
        const functionResponseParts: any[] = [];
        let toolResultText = "";

        if (call.name === 'generate_image') {
          const prompt = call.args['prompt'] as string;

          // Show "Generating..." status in UI
          setMessages(prev => [...prev, { id: 'sys-'+Date.now(), role: 'model', text: '', isTyping: true, toolUse: 'Visualizing consequence...' }]);

          try {
            const imageData = await generateSimulationImage(prompt);
            setLastImage(imageData); // Update context for editing

            // Remove the loading indicator and add the image message
            setMessages(prev => {
                const filtered = prev.filter(m => !m.isTyping);
                return [...filtered, {
                    id: 'img-'+Date.now(),
                    role: 'model',
                    text: `Generated: ${prompt}`,
                    image: imageData
                }];
            });

            toolResultText = "Image generated successfully and displayed to user.";

          } catch (e) {
            console.error("Image gen error", e);
            toolResultText = "Error: Failed to generate image.";
            setMessages(prev => prev.filter(m => !m.isTyping)); // Clear loading
          }
        } 
        else if (call.name === 'edit_image') {
          const instruction = call.args['instruction'] as string;

          if (!lastImage) {
            toolResultText = "Error: No previous image found to edit. Ask user to generate one first.";
          } else {
             // Show "Editing..." status
            setMessages(prev => [...prev, { id: 'sys-'+Date.now(), role: 'model', text: '', isTyping: true, toolUse: 'Applying changes...' }]);

            try {
              const imageData = await editSimulationImage(lastImage, instruction);
              setLastImage(imageData);

               setMessages(prev => {
                const filtered = prev.filter(m => !m.isTyping);
                return [...filtered, {
                    id: 'img-edit-'+Date.now(),
                    role: 'model',
                    text: `Edited: ${instruction}`,
                    image: imageData
                }];
              });

              toolResultText = "Image edited successfully and displayed to user.";
            } catch (e) {
              console.error("Image edit error", e);
              toolResultText = "Error: Failed to edit image.";
              setMessages(prev => prev.filter(m => !m.isTyping));
            }
          }
        }

        // Send function response back to model
        functionResponseParts.push({
            functionResponse: {
                name: call.name,
                response: { result: toolResultText }
            }
        });

        // Get the model's follow-up text
        result = await chat.sendMessage(functionResponseParts);
      }

      // Add the final text response from model (if any)
      if (result.text) {
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            role: 'model',
            text: result.text
        }]);
      }

    } catch (err) {
      console.error("Simulation error", err);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "System Error: The simulation engine encountered a glitch. Please try again."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // --- RENDER: SETUP SCREEN ---
  if (needsSetup) {
    return (
        <div className="flex flex-col h-[600px] max-w-2xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
             <button onClick={onExit} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors z-10">
                <XCircle className="w-8 h-8" />
            </button>
            <div className="flex flex-col items-center justify-center h-full text-center space-y-8 p-8 relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-indigo-50 to-transparent"></div>

                <div className="relative z-10 bg-white p-4 rounded-full shadow-lg border border-indigo-100 mb-4 animate-bounce-slow">
                    <Gamepad2 className="w-12 h-12 text-indigo-600" />
                </div>

                <div className="relative z-10 max-w-md">
                    <h2 className="text-3xl font-bold mb-2 text-slate-800">Career Simulator</h2>
                    <p className="text-slate-500 text-lg">Experience a "Day in the Life" of your dream job before you commit.</p>
                </div>

                <form onSubmit={handleSetupSubmit} className="w-full max-w-sm space-y-5 relative z-10">
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Your Name</label>
                        <input 
                            type="text" 
                            required
                            value={setupData.name}
                            onChange={(e) => setSetupData({...setupData, name: e.target.value})}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 shadow-sm"
                            placeholder="e.g. David"
                        />
                    </div>
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Job Role to Simulate</label>
                        <div className="relative">
                            <Briefcase className="absolute left-3 top-3.5 w-5 h-5 text-slate-400" />
                            <input 
                                type="text" 
                                required
                                value={setupData.role}
                                onChange={(e) => setSetupData({...setupData, role: e.target.value})}
                                className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 pl-10 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 font-semibold shadow-sm"
                                placeholder="e.g. Digital Marketer"
                            />
                        </div>
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold text-lg hover:bg-indigo-700 hover:shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0 flex items-center justify-center gap-2"
                    >
                        <Play className="w-5 h-5 fill-current" /> Start Simulation
                    </button>
                </form>
            </div>
        </div>
    );
  }

  // --- RENDER: CHAT INTERFACE ---
  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
        {/* Header */}
        <div className="p-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-indigo-100 p-2 rounded-lg border border-indigo-200">
                    <Gamepad2 className="w-5 h-5 text-indigo-600" />
                </div>
                <div>
                    <h2 className="font-bold text-slate-800 text-lg hidden sm:block">Career Simulator</h2>
                    <div className="flex items-center gap-1.5 text-xs">
                         <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                         <span className="text-slate-500 uppercase tracking-wide font-medium">Role:</span>
                         <span className="font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">
                            {initialRole || setupData.role}
                         </span>
                    </div>
                </div>
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={handleRestart}
                    className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    title="Restart Simulation"
                >
                    <RotateCcw className="w-5 h-5" />
                </button>
                <button 
                    onClick={onExit} 
                    className="group flex items-center gap-2 px-3 py-1.5 rounded-lg text-slate-500 hover:bg-red-50 hover:text-red-600 transition-colors border border-transparent hover:border-red-100"
                >
                    <span className="text-xs font-bold group-hover:underline decoration-red-300">EXIT</span>
                    <XCircle className="w-5 h-5" />
                </button>
            </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-slate-50/50">
            {messages.map((msg) => (
            <div 
                key={msg.id} 
                className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm border ${
                    msg.role === 'user' 
                        ? 'bg-indigo-600 border-indigo-600' 
                        : 'bg-white border-slate-200'
                }`}>
                    {msg.role === 'user' 
                        ? <User className="w-5 h-5 text-white" /> 
                        : <Bot className="w-5 h-5 text-indigo-600" />
                    }
                </div>

                <div className={`max-w-[85%] md:max-w-[75%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>

                     {/* Tool Usage Indicator */}
                     {msg.toolUse && (
                        <div className="flex items-center gap-2 mb-2 px-3 py-1 bg-white border border-slate-200 rounded-full text-xs text-slate-500 font-medium shadow-sm w-fit animate-fadeIn">
                            {msg.isTyping ? <Loader2 className="w-3 h-3 animate-spin text-indigo-500" /> : <Wand2 className="w-3 h-3 text-indigo-500" />}
                            {msg.toolUse}
                        </div>
                     )}

                    {/* Image Bubble */}
                    {msg.image && (
                        <div className="mb-2 p-1.5 bg-white border border-slate-200 rounded-2xl shadow-sm animate-fadeIn">
                            <div className="relative rounded-xl overflow-hidden shadow-inner max-w-xs md:max-w-sm">
                                <img src={`data:image/png;base64,${msg.image}`} alt="Generated Content" className="w-full h-auto object-cover" />
                                <div className="absolute bottom-2 right-2 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded-full backdrop-blur-sm flex items-center gap-1">
                                    <ImageIcon className="w-3 h-3" /> Generated by AI
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Text Bubble */}
                    {(msg.text || (!msg.image && !msg.toolUse)) && (
                        <div className={`p-5 rounded-2xl shadow-sm leading-relaxed text-sm md:text-base ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap">{msg.text}</div>
                        </div>
                    )}

                    <span className="text-[10px] text-slate-400 mt-1 block px-1">
                        {msg.role === 'user' ? 'You' : 'Simulator'}
                    </span>
                </div>
            </div>
            ))}

            {isLoading && messages.length > 0 && !messages[messages.length-1].isTyping && (
                <div className="flex items-center gap-3 text-slate-400 pl-14 animate-fadeIn">
                    <div className="flex gap-1 h-2">
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '100ms'}}></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></div>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-slate-200">
            <ConversationalInput 
                value={input}
                onChange={setInput}
                onSubmit={handleSend}
                placeholder="Make a decision (e.g., 'Fix the server')..."
                autoFocus={true}
                enableVoice={true}
            />
            <div className="mt-3 flex items-start gap-2 text-xs text-slate-400 px-1 justify-center">
                <AlertCircle className="w-3 h-3 mt-0.5 text-indigo-400 flex-shrink-0" />
                <p>AI will test your choices. You can say <b>"Generate image of..."</b> to visualize ideas.</p>
            </div>
        </div>
    </div>
  );
};

export default SimulationSession;

import { GoogleGenAI, Type, Schema, Chat, FunctionDeclaration, Tool } from "@google/genai";
import { ANALYSIS_PROMPT } from "../constants";
import { CareerAdviceResponse, FileData, Pathway, FutureVision } from "../types";

const apiKey = process.env.API_KEY;

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentProfile: {
      type: Type.OBJECT,
      properties: {
        summary: { type: Type.STRING, description: "A concise summary of the student's profile (max 100 words)." },
        keyStrengths: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["summary", "keyStrengths"]
    },
    contextAnalysis: { type: Type.STRING, description: "Analysis of their situation and constraints." },
    reflection: { type: Type.STRING, description: "A 'What I Heard' section reflecting the user's story back to them." },
    practicalPathTitle: { type: Type.STRING, description: "Title of the realistic, near-term career path." },
    growthPathTitle: { type: Type.STRING, description: "Title of the aspirational, long-term career path." },
    reasoning: { type: Type.STRING, description: "Why these two paths were chosen." }
  },
  required: ["studentProfile", "contextAnalysis", "reflection", "practicalPathTitle", "growthPathTitle", "reasoning"]
};

const pathwaySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    fitReason: { type: Type.STRING, description: "Why this fits the user (max 2 sentences)." },
    requiredSkills: {
      type: Type.OBJECT,
      properties: {
        technical: { type: Type.ARRAY, items: { type: Type.STRING } },
        soft: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["technical", "soft"]
    },
    educationOptions: { type: Type.ARRAY, items: { type: Type.STRING } },
    timeline: { type: Type.STRING, description: "e.g., '6-12 months'" },
    challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
    actionSteps: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3-5 concrete starting steps." },
    marketReality: { type: Type.STRING, description: "Current demand and job availability." },
    realityCheck: { type: Type.STRING, description: "A grounded 'Reality Check' regarding common traps or local context." },
    salaryRange: {
      type: Type.OBJECT,
      properties: {
        min: { type: Type.NUMBER },
        max: { type: Type.NUMBER },
        currency: { type: Type.STRING, description: "Local currency code e.g. NGN, USD" }
      },
      required: ["min", "max", "currency"]
    },
    demandScore: { type: Type.NUMBER, description: "0 to 100" },
    growthScore: { type: Type.NUMBER, description: "0 to 100" }
  },
  required: ["title", "fitReason", "requiredSkills", "educationOptions", "timeline", "challenges", "actionSteps", "marketReality", "realityCheck", "salaryRange", "demandScore", "growthScore"]
};

// Helper to remove markdown code blocks if the model includes them
const cleanJson = (text: string): string => {
  return text.replace(/```json\n?|```/g, '').trim();
};

export const generateCareerAdvice = async (
  textInput: string,
  files: FileData[]
): Promise<CareerAdviceResponse> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });
  // Switched to Gemini 3 Pro for superior reasoning capabilities
  const modelName = "gemini-3-pro-preview"; 

  // Prepare input parts
  const analysisParts: any[] = [];
  if (files && files.length > 0) {
    files.forEach(file => {
      analysisParts.push({
        inlineData: { mimeType: file.mimeType, data: file.data }
      });
    });
  }
  analysisParts.push({ text: `Student Scenario: ${textInput}` });

  // --- STEP 1: ANALYSIS ---
  let analysisResult: any;
  try {
    console.log("Step 1: Analyzing Profile with Gemini 3 Pro...");
    const analysisResponse = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: analysisParts },
      config: {
        systemInstruction: ANALYSIS_PROMPT,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.3,
      }
    });

    if (!analysisResponse.text) throw new Error("Empty response from AI");
    analysisResult = JSON.parse(cleanJson(analysisResponse.text));
  } catch (error) {
    console.error("Step 1 Failed:", error);
    throw new Error("Failed to analyze profile. Please try again.");
  }

  // --- STEP 2 & 3: PATHWAY GENERATION (PARALLEL) ---
  console.log("Step 2: Generating Pathways...");

  const generatePathway = async (title: string, type: 'Practical' | 'Growth'): Promise<Pathway> => {
    const prompt = `
      Create a detailed ${type} Career Pathway for the role: "${title}".

      Student Context:
      ${JSON.stringify(analysisResult.studentProfile)}
      ${analysisResult.contextAnalysis}

      Requirements:
      - Be realistic for the African/Nigerian context if applicable.
      - Estimate salary ranges in local currency based on your knowledge.
      - Keep text concise and actionable.
      - Do NOT use placeholder values (e.g., 0, "TBD"). Estimate best available data.
    `;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: { role: "user", parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: pathwaySchema,
        temperature: 0.4,
      }
    });

    if (!response.text) throw new Error("Empty pathway response");
    return JSON.parse(cleanJson(response.text)) as Pathway;
  };

  try {
    const [practicalPathway, growthPathway] = await Promise.all([
      generatePathway(analysisResult.practicalPathTitle, 'Practical'),
      generatePathway(analysisResult.growthPathTitle, 'Growth')
    ]);

    return {
      studentProfile: analysisResult.studentProfile,
      contextAnalysis: analysisResult.contextAnalysis,
      reflection: analysisResult.reflection,
      practicalPathway,
      growthPathway,
      closingMessage: "Your personalized career roadmap is ready. Remember, these are starting points—your journey is yours to define."
    };

  } catch (error) {
    console.error("Step 2 Failed:", error);
    throw new Error("Failed to generate detailed pathways. Please try again.");
  }
};

