import React, { useState, useEffect, useRef } from 'react';
import { Chat, GenerateContentResponse } from '@google/genai';
import { createSimulationSession, generateSimulationImage, editSimulationImage } from '../services/geminiService';
import { ChatMessage } from '../types';
import { User, Gamepad2, AlertCircle, XCircle, Play, ChevronRight, Briefcase, Bot, Image as ImageIcon, Wand2, Loader2, RotateCcw } from 'lucide-react';
import ConversationalInput from './ConversationalInput';

interface SimulationSessionProps {
  initialRole?: string;
  initialContext?: string;
  onExit: () => void;
}

const SimulationSession: React.FC<SimulationSessionProps> = ({ initialRole, initialContext, onExit }) => {
  const [chat, setChat] = useState<Chat | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Use Ref for image persistence to avoid closure staleness in async loops
  const lastImageRef = useRef<string | null>(null); 
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Setup State for manual entry
  const [needsSetup, setNeedsSetup] = useState(!initialRole);
  const [setupData, setSetupData] = useState({ role: initialRole || '', name: 'Student' });

  useEffect(() => {
    // If we have data immediately, start. Otherwise wait for setup form.
    if (!needsSetup && initialRole) {
      initSession(initialRole, initialContext || `User: ${setupData.name}`);
    }
  }, [initialRole, needsSetup]);

  const initSession = (role: string, context: string) => {
    try {
      const session = createSimulationSession(role, context);
      setChat(session);

      setIsLoading(true);
      // Trigger the "Setup" phase explicitly
      session.sendMessage({ message: "Begin the simulation. Generate the starting image of the workplace immediately." }).then((response) => {
          const text = response.candidates?.[0]?.content?.parts?.map(p => p.text).join('') || "Loading simulation...";
          setMessages([{
            id: 'init',
            role: 'model',
            text: text
          }]);

          // If init message has function calls (unlikely but possible), we might miss them here 
          // but usually the first turn is just text setup or simple generation. 
          // For robustness, we could use handleResponseLoop here too, but simple init is usually fine.
          setIsLoading(false);
      });
    } catch (e) {
      console.error("Failed to init simulation", e);
    }
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSetupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (setupData.role.trim()) {
        setNeedsSetup(false);
        initSession(setupData.role, `User Name: ${setupData.name}. Custom Simulation Request.`);
    }
  };

  const handleRestart = () => {
    setMessages([]);
    lastImageRef.current = null;
    if (initialRole) {
      initSession(initialRole, initialContext || `User: ${setupData.name}`);
    } else {
      initSession(setupData.role, `User Name: ${setupData.name}. Custom Simulation Request.`);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || !chat || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      let result = await chat.sendMessage({ message: userMsg.text });

      // Loop to handle potential multi-turn tool usage (Model -> Tool -> Model -> Tool...)
      while (true) {
        // 1. Extract and display TEXT parts immediately
        // We iterate parts manually to avoid the "non-text parts" warning from the SDK
        const parts = result.candidates?.[0]?.content?.parts || [];
        let textContent = '';
        for (const part of parts) {
            if (part.text) textContent += part.text;
        }

        if (textContent) {
            setMessages(prev => [...prev, {
                id: 'msg-' + Date.now() + Math.random(),
                role: 'model',
                text: textContent
            }]);
        }

        // 2. Check for FUNCTION CALLS
        if (result.functionCalls && result.functionCalls.length > 0) {
            const functionResponseParts: any[] = [];

            for (const call of result.functionCalls) {
                 // Ephemeral Loading Message for Tool Action
                 const loadingId = 'loading-' + Date.now();
                 const loadingText = call.name === 'generate_image' ? 'Generating visualization...' : 'Updating visualization...';

                 setMessages(prev => [...prev, { 
                    id: loadingId, 
                    role: 'model', 
                    text: '', 
                    isTyping: true, 
                    toolUse: loadingText 
                 }]);

                 let toolResultText = "";

                 try {
                    if (call.name === 'generate_image') {
                        const prompt = call.args['prompt'] as string;
                        const imageData = await generateSimulationImage(prompt);
                        lastImageRef.current = imageData;

                        // Replace loading with Image Message
                        setMessages(prev => prev.filter(m => m.id !== loadingId).concat({
                            id: 'img-' + Date.now(),
                            role: 'model',
                            text: `Generated: ${prompt}`,
                            image: imageData
                        }));
                        toolResultText = "Image generated successfully.";
                    } 
                    else if (call.name === 'edit_image') {
                        const instruction = call.args['instruction'] as string;
                        if (!lastImageRef.current) {
                             toolResultText = "Error: No previous image found to edit.";
                             setMessages(prev => prev.filter(m => m.id !== loadingId));
                        } else {
                             const imageData = await editSimulationImage(lastImageRef.current, instruction);
                             lastImageRef.current = imageData;

                             setMessages(prev => prev.filter(m => m.id !== loadingId).concat({
                                id: 'img-edit-' + Date.now(),
                                role: 'model',
                                text: `Edited: ${instruction}`,
                                image: imageData
                            }));
                            toolResultText = "Image edited successfully.";
                        }
                    } else {
                         toolResultText = "Error: Unknown function.";
                         setMessages(prev => prev.filter(m => m.id !== loadingId));
                    }
                 } catch (e) {
                     console.error("Tool execution error", e);
                     toolResultText = "Error: Tool execution failed.";
                     setMessages(prev => prev.filter(m => m.id !== loadingId));
                 }

                 functionResponseParts.push({
                    functionResponse: {
                        name: call.name,
                        response: { result: toolResultText }
                    }
                });
            }

            // Send tool outputs back to model and get the NEXT response
            // This updates 'result' so the loop continues to check the next response
            result = await chat.sendMessage({ message: functionResponseParts });

        } else {
            // No function calls? We are done with this turn.
            break;
        }
      }

    } catch (err) {
      console.error("Simulation error", err);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "System Error: The simulation engine encountered a glitch. Please try again."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // --- RENDER: SETUP SCREEN ---
  if (needsSetup) {
    return (
        <div className="flex flex-col h-[600px] max-w-2xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
             <button onClick={onExit} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors z-10">
                <XCircle className="w-8 h-8" />
            </button>
            <div className="flex flex-col items-center justify-center h-full text-center space-y-8 p-8 relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-indigo-50 to-transparent"></div>

                <div className="relative z-10 bg-white p-4 rounded-full shadow-lg border border-indigo-100 mb-4 animate-bounce-slow">
                    <Gamepad2 className="w-12 h-12 text-indigo-600" />
                </div>

                <div className="relative z-10 max-w-md">
                    <h2 className="text-3xl font-bold mb-2 text-slate-800">Career Simulator</h2>
                    <p className="text-slate-500 text-lg">Experience a "Day in the Life" of your dream job before you commit.</p>
                </div>

                <form onSubmit={handleSetupSubmit} className="w-full max-w-sm space-y-5 relative z-10">
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Your Name</label>
                        <input 
                            type="text" 
                            required
                            value={setupData.name}
                            onChange={(e) => setSetupData({...setupData, name: e.target.value})}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 shadow-sm"
                            placeholder="e.g. David"
                        />
                    </div>
                    <div className="text-left">
                        <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Job Role to Simulate</label>
                        <div className="relative">
                            <Briefcase className="absolute left-3 top-3.5 w-5 h-5 text-slate-400" />
                            <input 
                                type="text" 
                                required
                                value={setupData.role}
                                onChange={(e) => setSetupData({...setupData, role: e.target.value})}
                                className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 pl-10 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all mt-1 font-semibold shadow-sm"
                                placeholder="e.g. Digital Marketer"
                            />
                        </div>
                    </div>
                    <button 
                        type="submit"
                        className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold text-lg hover:bg-indigo-700 hover:shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0 flex items-center justify-center gap-2"
                    >
                        <Play className="w-5 h-5 fill-current" /> Start Simulation
                    </button>
                </form>
            </div>
        </div>
    );
  }

  // --- RENDER: CHAT INTERFACE ---
  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fadeIn relative">
        {/* Header */}
        <div className="p-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-indigo-100 p-2 rounded-lg border border-indigo-200">
                    <Gamepad2 className="w-5 h-5 text-indigo-600" />
                </div>
                <div>
                    <h2 className="font-bold text-slate-800 text-lg hidden sm:block">Career Simulator</h2>
                    <div className="flex items-center gap-1.5 text-xs">
                         <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                         <span className="text-slate-500 uppercase tracking-wide font-medium">Role:</span>
                         <span className="font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">
                            {initialRole || setupData.role}
                         </span>
                    </div>
                </div>
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={handleRestart}
                    className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    title="Restart Simulation"
                >
                    <RotateCcw className="w-5 h-5" />
                </button>
                <button 
                    onClick={onExit} 
                    className="group flex items-center gap-2 px-3 py-1.5 rounded-lg text-slate-500 hover:bg-red-50 hover:text-red-600 transition-colors border border-transparent hover:border-red-100"
                >
                    <span className="text-xs font-bold group-hover:underline decoration-red-300">EXIT</span>
                    <XCircle className="w-5 h-5" />
                </button>
            </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-slate-50/50">
            {messages.map((msg) => (
            <div 
                key={msg.id} 
                className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
                <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm border ${
                    msg.role === 'user' 
                        ? 'bg-indigo-600 border-indigo-600' 
                        : 'bg-white border-slate-200'
                }`}>
                    {msg.role === 'user' 
                        ? <User className="w-5 h-5 text-white" /> 
                        : <Bot className="w-5 h-5 text-indigo-600" />
                    }
                </div>

                <div className={`max-w-[85%] md:max-w-[75%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>

                     {/* Tool Usage Indicator */}
                     {msg.toolUse && (
                        <div className="flex items-center gap-2 mb-2 px-3 py-1 bg-white border border-slate-200 rounded-full text-xs text-slate-500 font-medium shadow-sm w-fit animate-fadeIn">
                            {msg.isTyping ? <Loader2 className="w-3 h-3 animate-spin text-indigo-500" /> : <Wand2 className="w-3 h-3 text-indigo-500" />}
                            {msg.toolUse}
                        </div>
                     )}

                    {/* Image Bubble */}
                    {msg.image && (
                        <div className="mb-2 p-1.5 bg-white border border-slate-200 rounded-2xl shadow-sm animate-fadeIn">
                            <div className="relative rounded-xl overflow-hidden shadow-inner max-w-xs md:max-w-sm">
                                <img src={`data:image/png;base64,${msg.image}`} alt="Generated Content" className="w-full h-full object-cover" />
                                <div className="absolute bottom-2 right-2 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded-full backdrop-blur-sm flex items-center gap-1">
                                    <ImageIcon className="w-3 h-3" /> Generated by AI
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Text Bubble */}
                    {(msg.text || (!msg.image && !msg.toolUse)) && (
                        <div className={`p-5 rounded-2xl shadow-sm leading-relaxed text-sm md:text-base ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap">{msg.text}</div>
                        </div>
                    )}

                    <span className="text-[10px] text-slate-400 mt-1 block px-1">
                        {msg.role === 'user' ? 'You' : 'Simulator'}
                    </span>
                </div>
            </div>
            ))}

            {isLoading && messages.length > 0 && !messages[messages.length-1].isTyping && (
                <div className="flex items-center gap-3 text-slate-400 pl-14 animate-fadeIn">
                    <div className="flex gap-1 h-2">
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '100ms'}}></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></div>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-slate-200">
            <ConversationalInput 
                value={input}
                onChange={setInput}
                onSubmit={handleSend}
                placeholder="Make a decision (e.g., 'Fix the server')..."
                autoFocus={true}
                enableVoice={true}
            />
            <div className="mt-3 flex items-start gap-2 text-xs text-slate-400 px-1 justify-center">
                <AlertCircle className="w-3 h-3 mt-0.5 text-indigo-400 flex-shrink-0" />
                <p>AI will test your choices. You can say <b>"Generate image of..."</b> to visualize ideas.</p>
            </div>
        </div>
    </div>
  );
};

export default SimulationSession;

import React, { useState } from 'react';
import { Compass, Sparkles, Mic, MessageSquare, MessageCircle, Gamepad2, History, Zap } from 'lucide-react';
import { AppState, CareerAdviceResponse, FileData, UserProfile, Pathway, ChatMessage, SavedSession } from './types';
import { generateCareerAdvice } from './services/geminiService';
import { saveSession } from './services/storage';
import InputForm from './components/InputForm';
import ResultView from './components/ResultView';
import LoadingScreen from './components/LoadingScreen';
import VoiceSession from './components/VoiceSession';
import ChatSession from './components/ChatSession';
import SimulationSession from './components/SimulationSession';
import HistoryModal from './components/HistoryModal';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<CareerAdviceResponse | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [mode, setMode] = useState<'text' | 'voice' | 'chat' | 'simulator'>('text');

  // State for Simulation
  const [simulationParams, setSimulationParams] = useState<{role: string, context: string} | null>(null);

  // State for Chat History restoration
  const [chatHistoryData, setChatHistoryData] = useState<ChatMessage[] | undefined>(undefined);

  // State for History Modal
  const [showHistory, setShowHistory] = useState(false);

  // Lifted Input State
  const [profile, setProfile] = useState<UserProfile>({
    name: '',
    situation: '',
    interests: [],
    constraints: [],
    dreams: '',
    concerns: ''
  });
  const [inputStep, setInputStep] = useState(0);

  const handleAnalyze = async (text: string, files: FileData[]) => {
    setAppState(AppState.ANALYZING);
    setErrorMsg(null);

    try {
      const data = await generateCareerAdvice(text, files);
      setResult(data);
      setAppState(AppState.RESULTS);
      // Auto-save successful results
      saveSession('advisor', data);
    } catch (err: any) {
      console.error(err);
      let msg = "Something went wrong while connecting to CareerSage.";
      if (err.message) msg += ` Details: ${err.message}`;

      setErrorMsg(msg);
      setAppState(AppState.ERROR);
    }
  };

  const getProfileNarrative = () => {
    return `
      My name is ${profile.name || "Student"}. 
      Current Situation: ${profile.situation}.
      My Interests: ${profile.interests.join(', ')}.
      My Constraints/Context: ${profile.constraints.join(', ')}.
      My Dreams/Goals: ${profile.dreams}.
      Additional Concerns: ${profile.concerns}.
      (Note: This request was triggered from a Voice Session).
    `;
  };

  const handleVoiceReportGeneration = () => {
    setMode('text');
    handleAnalyze(getProfileNarrative(), []);
  };

  const startSimulation = (pathway: Pathway) => {
    setSimulationParams({
      role: pathway.title,
      context: `User Name: ${profile.name || 'User'}. Background: ${profile.situation || 'N/A'}. Interests: ${profile.interests.join(', ')}.`
    });
    setMode('simulator');
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setErrorMsg(null);
    setInputStep(0);
    setSimulationParams(null);
    setChatHistoryData(undefined); // Clear chat history reset
    setProfile({
        name: '',
        situation: '',
        interests: [],
        constraints: [],
        dreams: '',
        concerns: ''
    });
  };

  const switchMode = (newMode: 'text' | 'voice' | 'chat' | 'simulator') => {
    // If we switch away from chat voluntarily, we clear the restored history
    // so next time it starts fresh (unless loaded from history again)
    if (mode === 'chat' && newMode !== 'chat') {
        setChatHistoryData(undefined);
    }
    setMode(newMode);

    if (mode === 'simulator' && newMode !== 'simulator') {
      setSimulationParams(null);
    }
  };

  const handleManualSimulationStart = () => {
    setSimulationParams(null); 
    setMode('simulator');
  };

  const handleRestoreSession = (session: SavedSession) => {
    setShowHistory(false);
    if (session.type === 'advisor') {
        setMode('text');
        setResult(session.data as CareerAdviceResponse);
        setAppState(AppState.RESULTS);
    } else if (session.type === 'chat') {
        setChatHistoryData(session.data as ChatMessage[]);
        setMode('chat');
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-800 bg-transparent">
      {/* Header - Glassmorphism */}
      <header className="glass-panel sticky top-4 z-40 mx-4 md:mx-auto max-w-7xl rounded-2xl shadow-sm mt-4">
        <div className="px-4 md:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer group" onClick={resetApp}>
            <div className="bg-gradient-to-tr from-emerald-600 to-teal-500 p-1.5 rounded-xl shadow-lg shadow-emerald-500/20 group-hover:scale-105 transition-transform">
              <Compass className="w-5 h-5 text-white" />
            </div>
            <div className="hidden md:block">
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-emerald-800 to-teal-600 tracking-tight">
                CareerSage
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
             {/* Tech Badge for Judges */}
             <div className="hidden lg:flex items-center gap-1.5 px-3 py-1 bg-white/50 border border-white rounded-full text-[11px] font-bold text-indigo-600 tracking-tight shadow-sm backdrop-blur-sm">
                <Zap className="w-3.5 h-3.5 fill-current" />
                <span>Gemini 3 Pro</span>
             </div>

             {/* Mode Toggle - Floating Island style */}
            <div className="flex bg-slate-100/80 backdrop-blur-sm rounded-full p-1 border border-white/50 shadow-inner">
                <button
                onClick={() => switchMode('text')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'text' ? 'bg-white text-emerald-700 shadow-sm ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700 hover:bg-white/50'}`}
                >
                <MessageSquare className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Advisor</span>
                </button>
                <button
                onClick={() => switchMode('voice')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'voice' ? 'bg-white text-emerald-700 shadow-sm ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700 hover:bg-white/50'}`}
                >
                <Mic className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Voice</span>
                </button>
                <button
                onClick={() => switchMode('chat')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all duration-300 ${mode === 'chat' ? 'bg-white text-emerald-700 shadow-sm ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700 hover:bg-white/50'}`}
                >
                <MessageCircle className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Chat</span>
                </button>
                <button
                onClick={handleManualSimulationStart}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold transition-all duration-300 ${mode === 'simulator' ? 'bg-indigo-600 text-white shadow-md shadow-indigo-500/30' : 'text-indigo-600 hover:bg-indigo-50/50'}`}
                >
                <Gamepad2 className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">Sim</span>
                </button>
            </div>

            {/* History Button */}
            <button 
                onClick={() => setShowHistory(true)}
                className="p-2.5 rounded-full bg-white/60 text-slate-600 hover:bg-white hover:text-emerald-700 transition-all border border-white/50 shadow-sm hover:shadow-md"
                title="History"
            >
                <History className="w-4 h-4" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-5xl mx-auto px-4 md:px-6 py-8 md:py-12 relative">

        {mode === 'voice' && (
          <VoiceSession 
            onEndSession={() => switchMode('text')} 
            userProfile={profile}
            onGenerateReport={handleVoiceReportGeneration}
          />
        )}

        {mode === 'chat' && (
           <ChatSession initialMessages={chatHistoryData} />
        )}

        {mode === 'simulator' && (
            <SimulationSession 
              initialRole={simulationParams?.role}
              initialContext={simulationParams?.context}
              onExit={() => switchMode('text')}
            />
        )}

        {mode === 'text' && (
          <>
            {appState === AppState.IDLE && (
              <div className="animate-fadeIn">
                <div className="text-center max-w-2xl mx-auto mb-10 md:mb-14">
                  <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/60 backdrop-blur-sm text-emerald-700 text-xs font-bold rounded-full mb-4 border border-white shadow-sm">
                     <Sparkles className="w-3 h-3 text-emerald-500" /> AI Career Counselor
                  </div>
                  <h2 className="text-3xl md:text-5xl font-bold text-slate-800 mb-4 tracking-tight leading-tight">
                     Find your path with <br/> <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 to-teal-500">Intelligent Guidance</span>
                  </h2>
                  <p className="text-slate-600 text-base md:text-lg leading-relaxed max-w-xl mx-auto">
                    A comprehensive career system that understands your local reality, 
                    powered by the reasoning of Gemini 3 Pro.
                  </p>
                </div>

                <InputForm 
                  profile={profile}
                  setProfile={setProfile}
                  currentStep={inputStep}
                  setCurrentStep={setInputStep}
                  onSubmit={handleAnalyze} 
                  isLoading={false} 
                />

              </div>
            )}

            {appState === AppState.ANALYZING && <LoadingScreen />}

            {appState === AppState.ERROR && (
              <div className="max-w-md mx-auto text-center py-20 animate-fadeIn glass-card rounded-3xl p-8">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-red-50 mb-6">
                  <Compass className="w-8 h-8 text-red-500" />
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Analysis Failed</h3>
                <p className="text-slate-600 mb-6">{errorMsg}</p>
                <button
                  onClick={() => setAppState(AppState.IDLE)}
                  className="px-8 py-3 bg-slate-900 text-white rounded-xl font-semibold hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5"
                >
                  Try Again
                </button>
              </div>
            )}

            {appState === AppState.RESULTS && result && (
              <ResultView 
                data={result} 
                onReset={resetApp} 
                onSimulate={startSimulation}
              />
            )}
          </>
        )}
      </main>

      <HistoryModal 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        onSelectSession={handleRestoreSession} 
      />

      {/* Footer */}
      <footer className="py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-xs font-medium text-slate-400">
            Built for the Google DeepMind Vibe Code Hackathon
          </p>
        </div>
      </footer>
    </div>
  );
};

